86	\title{Slack, Quotient Cores, and the Entropy Gap\\ for Smooth-Domain Reed--Solomon Codes\\\large List fibers, cyclotomic rigidity, Galois-amplified collisions,\\\large and the corrected slack mutual-correlated-agreement theory}
87	\author{Przemek Chojecki\\ \small ulam.ai}
88	\date{\today}
