1462	\part{Transfers, caps, and repairs}
1463	
1464	\section{A universal field-size cap via list-to-agreement conversion}\label{sec:cap}
1465	
1466	The imported Crites--Stewart conversion states that correlated agreement with sufficiently small error forces small list sizes \cite{CS25}; the survey \cite{ABF26} records this as the basic conversion between the two grand challenges.  Composing the contrapositive with the quotient-core lists of \cref{thm:qcore} conditionally caps the achievable mutual-correlated-agreement threshold over \emph{every} field of challenge size, prime or extension, with no value-set counting at all.  Throughout, $\eca(C,\delta)$ denotes the correlated-agreement error in the normalization of \cref{def:mca}: the maximal density of parameters $z$ for which $f+zg$ is $\delta$-close to $C$ while no common agreement set of density $1-\delta$ explains $f$ and $g$ simultaneously.  Every such $z$ is in particular support-wise MCA-bad, so
1467	\begin{equation}\label{eq:camca}
1468	        \emca(C,\delta)\ \ge\ \eca(C,\delta).
1469	\end{equation}
1470	
1471	\begin{theorem}[Imported: list-to-agreement conversion; \cite{CS25}, Theorem~2, as restated in \cite{ABF26}]\label{thm:capimport}
1472	Let $C=\RS[\F_q,D,k]$ with $|D|=n$, and let $\delta\in(0,1-\rho]$.  If
1473	\[
1474	        \eca(C,\delta)\ \le\ \eta\left(\frac1k-\frac n{kq}\right)
1475	        \qquad\text{for some }\eta\in(0,1),
1476	\]
1477	then the $\delta$-list size of the relevant augmented code $C^+\supseteq C$ satisfies $\Lst(C^+,\delta)\le\lceil q\,\eca(C,\delta)/(1-\eta)\rceil$.  We use only the consequence $\Lst(C,\delta)\le\Lst(C^+,\delta)$; see \cref{rem:diligence} for the bookkeeping this import requires.
1478	\end{theorem}
1479	
1480	\begin{lemma}[Contrapositive at $\eta=1/2$]\label{lem:capcontra}
1481	Under the import, if $\Lst(C,\delta)>q/k+1$, then $\eca(C,\delta)>\frac1{2k}\left(1-\frac nq\right)$.
1482	\end{lemma}
1483	
1484	\begin{proof}
1485	If instead $\eca\le\frac1{2k}(1-\frac nq)=\frac12(\frac1k-\frac n{kq})$, then \cref{thm:capimport} at $\eta=\frac12$ gives $\Lst(C,\delta)\le\lceil 2q\,\eca\rceil\le\lceil\frac qk(1-\frac nq)\rceil\le q/k+1$.
1486	\end{proof}
1487	
1488	\begin{theorem}[Universal cap, conditional on the import]\label{thm:cap}
1489	Let $q$ be any prime power, let $H\le\F_q^\times$ be smooth of order $n\le q/2$, and put $C=\RS[\F_q,H,k]$, where $k=\rho n$ and $\rho=2^{-a}$.  Let $N=2^c$ with $a\le c$, assume $N\mid n$, and put $M:=n/N\ge2$.  Suppose
1490	\[
1491	        \binom{N-1}{\rho N}\ >\ \frac qk+1.
1492	\]
1493	Then, conditional on \cref{thm:capimport},
1494	\[
1495	        \emca\Big(C,\,1-\rho-\frac{M-1}n\Big)\ >\ \frac1{2k}\Big(1-\frac nq\Big)\ \ge\ \frac1{4k},
1496	        \qquad\text{hence}\qquad
1497	        \delta^*_C\big(\tfrac1{4k}\big)\ <\ 1-\rho-\frac1{2N}.
1498	\]
1499	\end{theorem}
1500	
1501	\begin{proof}
1502	$M\mid k$ and $k/M=\rho N\le N-1$ hold by the divisibility hypotheses, so \cref{thm:qcore} at quotient order $N$ with $\sigma=M-1$ gives $\Lst(C,1-\rho-\frac{M-1}n)\ge\binom{N-1}{\rho N}>q/k+1$.  \Cref{lem:capcontra} converts this into $\eca>\frac1{2k}(1-\frac nq)$ at the same radius, and \cref{eq:camca} transfers it to $\emca$; $n\le q/2$ gives the clean constant.  Finally $\frac{M-1}n=\frac1N(1-\frac1M)\ge\frac1{2N}$ and $\emca(C,\cdot)$ is nondecreasing.
1503	\end{proof}
1504	
1505	\begin{corollary}[Two-tier answer at challenge parameters]\label{cor:captiers}
1506	Let $q\le2^{256}$ be any prime power, $\rho\in\{\frac12,\frac14,\frac18,\frac1{16}\}$, and let $H\le\F_q^\times$ be smooth of order $n$ with $2^{11}\mid n$, $n\le q/2$, and $k=\rho n\le2^{40}$, and put $C=\RS[\F_q,H,k]$.  Then, conditional on \cref{thm:capimport},
1507	\[
1508	        \delta^*_C(2^{-128})\ \le\ \delta^*_C(2^{-42})\ <\ 1-\rho-2^{-11}.
1509	\]
1510	Combined with \cref{prop:prize}: below the per-rate reach of roughly $2^{150}$--$2^{162}$ bits the challenge threshold is pinned below $1-\rho-\frac1{64}$ unconditionally, over every field up to $256$ bits it is pinned below $1-\rho-2^{-11}$ conditionally on the import, and below $1-\rho-2^{-9}$ ($2^{-10}$ at rate $1/16$) by the sharpened cap of \cite{UniversalCap}.
1511	\end{corollary}
1512	
1513	\begin{proof}
1514	Take $N=2^{10}$ in \cref{thm:cap}; the hypothesis $2^{11}\mid n$ ensures $M=n/N\ge2$.  Since $k\ge1$ and $q\le2^{256}$, we have $\log_2(q/k+1)\le257$, while $\log_2\binom{N-1}{\rho N}$ equals $1017.7$, $825.2$, $551.7$, and $341.0$ at the four rates, so the binomial hypothesis holds comfortably.  The constraint $k\le2^{40}$ enters only at the end: the cap gives $\emca\ge\frac1{4k}\ge2^{-42}>2^{-128}$ at gap at least $2^{-11}$.
1515	\end{proof}
1516	
1517	\begin{remark}[Relation to the companion cap paper]\label{rem:capcompanion}
1518	The composition above is extracted, sharpened, and made the main theorem of \cite{UniversalCap}: running the pigeonhole on slack-two locator fibers over the field of definition, rather than on quotient cores, improves the gap to $2^{-9}$ ($2^{-10}$ at rate $1/16$) under $2^{10}\mid n$ (resp.\ $2^{11}\mid n$), yields error $\frac1{2k}(1-n/q)\ge2^{-86}$ with no condition relating $n$ and $q$, and covers extension fields $\F\supseteq B\supseteq H$ directly through the subfield pigeonhole.  \Cref{thm:cap} is retained here because the quotient-core mechanism is the one native to this paper's framework and the proof is self-contained given Part~I; for citation purposes, the cap of \cite{UniversalCap} supersedes \cref{cor:captiers}.
1519	\end{remark}
1520	
1521	\begin{remark}[The pinch on the list--agreement equivalence]\label{rem:pinch}
1522	The survey \cite{ABF26} discusses the hoped-for equivalence ``lists small $\Leftrightarrow$ correlated agreement small'' in the regime $n\ll q$.  On smooth domains it is now pinched from both sides: \cref{thm:capimport} converts small agreement error into small lists, while the dyadic pigeonhole of \cref{thm:qcore} produces lists of size $2^{\Theta(N)}$ at gap $\Theta(1/N)$ for every divisor scale, which by the same conversion \emph{forces} agreement failure.  Any positive MCA theory above the corrected reserve must therefore live on domains where the divisor pigeonhole collapses --- which is precisely the structural definition of non-smoothness this paper has been quantifying.
1523	\end{remark}
1524	
1525	\begin{remark}[Due diligence on the import]\label{rem:diligence}
1526	\Cref{thm:capimport} is used as a black box, and three items must be checked against \cite{CS25} before the cap is cited as unconditional: (i) the exact admissible range of $\delta$ in their Theorem~2, and the definition of the augmented code $C^+$ together with the monotonicity $\Lst(C,\delta)\le\Lst(C^+,\delta)$; (ii) the normalization of $\eca$ (density over $z$, including extension-field sampling of $z$ in the sense of the proximity-gaps literature); (iii) the constants in the displayed implication.  Should any constant need repair, the slacked conversion of Ben-Sasson--Carmon--Hab\"ock--Kopparty--Saraf \cite{BCHKS25}, recorded as Theorem~5.2 of \cite{ABF26}, yields the same corollary with $2^{-42}$ replaced by a slightly smaller explicit constant and $2^{-11}$ by a slightly smaller gap.  The same checklist is adopted verbatim in \cite{UniversalCap}, whose slacked variant through \cite{BCHKS25} is worked out as an independent fallback route.
1527	\end{remark}
