1603	\section{Torsion-coset repairs: \texorpdfstring{$\{2,3\}$}{(2,3)}-smooth rigidity and arbitrary-base templates}\label{sec:torsion}
1604	
1605	We isolate the external input in exactly the form used, matching the pattern of \cref{thm:capimport,thm:torsionimport}.
1606	
1607	\begin{theorem}[Imported: vanishing sums over two primes; \cite{Sch64,CJ76,LL00}]\label{thm:vsimport}
1608	Let $n$ have prime support contained in $\{2,3\}$.  (i)~The $\Z$-module of solutions of $\sum_{y\in\mufn}h(y)\,y=0$ is generated by the rotations of the prime relations $R_p$ for the primes $p\mid n$ \cite{Sch64}.  (ii)~Every minimal vanishing sum of $n$-th roots of unity with nonnegative integer coefficients is a rotation of $R_p$ for some prime $p\mid n$ \cite{CJ76,LL00}.
1609	\end{theorem}
1610	
1611	\begin{theorem}[$\{2,3\}$-smooth slack-one rigidity, conditional on the import]\label{thm:23rigidity}
1612	Let $n=2^a3^b$ with $a\ge1$, and when $b\ge1$ let $\omega\in\mufn$ have order $3$.  A function $h:\mufn\to\Z$ satisfies $\sum_yh(y)\,y=0$ if and only if $h$ is a $\Z$-combination of the pair functions $\delta_\zeta+\delta_{-\zeta}$ and, when $b\ge1$, the triangle functions $\delta_\zeta+\delta_{\zeta\omega}+\delta_{\zeta\omega^2}$.  Moreover, for sets $S,T\subseteq\mufn$: $e_1(S)=e_1(T)$ if and only if the multiset $S\sqcup(-T)$ is an $\N$-linear combination of rotated pair relations $\{\zeta,-\zeta\}$ and, when $b\ge1$, rotated triangle relations $\{\zeta,\zeta\omega,\zeta\omega^2\}$.
1613	\end{theorem}
1614	
1615	\begin{proof}
1616	The displayed generators visibly lie in the kernel of $h\mapsto\sum_yh(y)\,y$; conversely the kernel is generated by them, by part~(i) of \cref{thm:vsimport}, since for $n=2^a3^b$ the rotated prime relations are exactly the pair functions and, when $b\ge1$, the triangle functions.  For the set version, suppose $e_1(S)=e_1(T)$.  Since $n$ is even, $-T\subseteq\mufn$, and $\sum_{y\in S}y+\sum_{y\in T}(-y)=0$ exhibits the multiset $S\sqcup(-T)$ --- multiplicities at most two, attained exactly when $y\in S$ and $-y\in T$ --- as a vanishing sum of $n$-th roots with nonnegative coefficients.  Every such sum decomposes as a sum of minimal vanishing sums with nonnegative coefficients, by induction on the total multiplicity: any nonempty vanishing sum contains a vanishing subsum of minimal cardinality, which is itself minimal, and removing it leaves a shorter vanishing sum.  By part~(ii) of \cref{thm:vsimport}, each minimal summand is a rotation of $R_p$ for a prime $p\mid n$: a pair, or a triangle when $b\ge1$.  This is the asserted $\N$-combination.  The converse is immediate, since every rotated pair and triangle sums to zero.  At $b=0$ only the pair relations occur, recovering the antipodal classification underlying \cref{thm:upstairs}.
1617	\end{proof}
1618	
1619	\begin{remark}[Mixed-radix counts and domains]\label{rem:23count}
1620	\Cref{thm:23rigidity} supplies the characteristic-zero relation-module and set-decomposition input for the $\{2,3\}$-smooth (mixed-radix FFT) extension of the slack-one theory.  The class invariant should consist of a signed pair profile together with a triangle profile, and the analogue of $\Acl(N',\ell')$ should be a two-parameter sum whose exponent is a constrained entropy maximization over pair and triangle densities.  The norm sieve itself transfers unchanged once the characteristic-zero classes are fixed, because the archimedean bounds never used $2$-smoothness.  The exact class enumeration and the corresponding two-parameter analogue of $\beta(\rho)$ are left as future combinatorics rather than claimed here; in particular, no canonical positive move normal form for set-to-set transformations is asserted.
1621	\end{remark}
1622	
1623	We isolate the external input in exactly the form used.
1624	
1625	\begin{theorem}[Imported: degree-only torsion-coset bound; \cite{AS12}, with \cite{Laurent84,ESS02,BS02}]\label{thm:torsionimport}
1626	For all $s,d\ge1$ there is an explicit constant $C_{\rm tc}(s,d)$ such that for every subvariety $V\subseteq\mathbb G_m^s$ cut out by polynomials of degree at most $d$, the torsion points of $V$ lie on at most $C_{\rm tc}(s,d)$ maximal torsion cosets contained in $V$, independently of the coefficients of the defining polynomials.
1627	\end{theorem}
1628	
1629	As with \cref{thm:capimport}, this statement is imported as a black box in exactly the form used, and \cref{thm:templates} below is conditional on it in the same sense.
1630	
1631	\begin{theorem}[Torsion-coset template structure for arbitrary-base slabs, conditional on the import]\label{thm:templates}
1632	Fix $s\ge1$, $\sigma\ge1$.  There is a constant $C(\sigma,s)$, independent of $n$ and of the pinned values, with the following property.  For any $c_1,\dots,c_\sigma\in\overline{\Q}$, let $V_c=\{x\in\mathbb G_m^s:\ p_i(x)=c_i,\ 1\le i\le\sigma\}$ be the slab variety in the power sums.  Then the torsion points of $V_c$ lie on at most $C(\sigma,s)$ maximal torsion cosets $u\mathcal H\subseteq V_c$.  Along each positive-dimensional coset all pinned power sums are constant (a padding family); the zero-dimensional cosets are at most $C(\sigma,s)$ isolated templates.  In particular, for every $n$ and every base, the characteristic-zero witness set of a $\sigma$-slab on $s$ letters decomposes into at most $C(\sigma,s)$ classes.
1633	\end{theorem}
1634	
1635	\begin{proof}
1636	Witnesses are torsion points of $\mathbb G_m^s$ on $V_c$.  Finiteness of the maximal torsion cosets is Laurent's theorem \cite{Laurent84}; the uniform count is \cref{thm:torsionimport} with $d=\sigma$, since the defining degrees $1,\dots,\sigma$ depend on neither $c$ nor $n$.  This gives $C(\sigma,s)=C_{\rm tc}(s,\sigma)$.  Constancy of the $p_i$ along a coset contained in $V_c$ holds by definition of $V_c$.
1637	\end{proof}
1638	
1639	\begin{corollary}[Finiteness of the residue-zero classification]\label{cor:reszero}
1640	For each fixed $(\sigma',s')$ the variety $\{e_2=\cdots=e_{\sigma'}=0\}$ has fixed coefficients, so \cref{thm:templates} reduces its torsion points to a finite, effectively computable list of coset families, uniformly in $n$.  Positive-dimensional cosets may still contain padding families of unbounded order; once those families are enumerated, the remaining isolated templates form a finite set.  Thus the residue-zero classification at $\sigma'\ge3$ left open after \cref{thm:selfinv} becomes a finite template computation for each fixed size.
1641	\end{corollary}
1642	
1643	\begin{remark}[The principled replacement for the retracted all-bases theorem]\label{rem:templaterepair}
1644	\Cref{thm:templates} is the structure that the retracted ``all bases, all non-dyadic directions'' claim was missing: every characteristic-zero witness of an arbitrary-base slab is ``one of at most $C(\sigma,s)$ templates, padded by vanishing-sum families,'' and the Newton-obstruction criterion of \cref{thm:allbasesdir} determines which templates survive a given direction.  Because the bases themselves are $n$-dependent torsion data, isolated templates can have unbounded order, so the finite-field transfer is per-class: the stable-range and density norm sieves of Part~II apply to each of the boundedly many classes separately.  Turning this into a clean every-prime arbitrary-base theorem would require carrying out that finite-template verification and the corresponding per-class norm-sieve bookkeeping; it is no longer a single rigidity shortcut.
1645	\end{remark}
